{
  "name": "lab-tech-landing",
  "version": "1.0.0",
  "private": true,
  "description": "Minimal production-ready landing page for a lab technician using Express, plain HTML/CSS/JS.",
  "main": "server.js",
  "scripts": {
    "start": "node server.js",
    "dev": "nodemon server.js",
    "test": "jest"
  },
  "dependencies": {
    "express": "^4.18.2"
  },
  "devDependencies": {
    "jest": "^29.7.0",
    "supertest": "^6.3.3",
    "jsdom": "^22.1.0",
    "nodemon": "^3.0.1"
  }
}

const path = require('path');
const express = require('express');

const app = express();

const publicDir = path.join(__dirname, 'public');

// Serve static assets from /public with basic caching rules
app.use(
  express.static(publicDir, {
    extensions: ['html'],
    maxAge: '1h',
    setHeaders: (res, filePath) => {
      if (path.extname(filePath) === '.html') {
        res.setHeader('Cache-Control', 'no-cache');
      }
    }
  })
);

// Health endpoint for uptime checks and tests
app.get('/health', (req, res) => {
  res.status(200).json({ status: 'ok' });
});

// Fallback to index.html for any other GET route (SPA behavior)
app.get('*', (req, res, next) => {
  if (req.path === '/health') return next();
  res.sendFile(path.join(publicDir, 'index.html'), (err) => {
    if (err) next(err);
  });
});

// Basic error logging/handling
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  // Basic error logging
  // eslint-disable-next-line no-console
  console.error('Server error:', err && err.stack ? err.stack : err);
  if (!res.headersSent) {
    res.status(500).json({ error: 'Internal Server Error' });
  }
});

const PORT = process.env.PORT ? parseInt(process.env.PORT, 10) : 3000;

// Start the server only when run directly
if (require.main === module) {
  app
    .listen(PORT, () => {
      // eslint-disable-next-line no-console
      console.log(`Server listening on http://localhost:${PORT}`);
    })
    .on('error', (err) => {
      // eslint-disable-next-line no-console
      console.error('Failed to start server:', err);
      process.exitCode = 1;
    });
}

module.exports = app;

:root {
  --red: #d32f2f;
  --black: #000000;
  --white: #ffffff;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
}

body {
  font-family: system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji";
  background: var(--white);
  color: var(--black);
  line-height: 1.5;
}

.hero {
  padding: 4rem 1rem;
  text-align: center;
  background: var(--black);
  color: var(--white);
}

.hero #hero-title {
  margin: 0 0 0.5rem 0;
  font-size: clamp(2rem, 5vw, 3rem);
}

.hero .subtitle {
  margin: 0;
  color: var(--red);
  font-weight: 500;
}

a { color: var(--red); }

document.addEventListener('DOMContentLoaded', () => {
  // Placeholder for client-side interactions (validation will be added later)
  // Keeping palette strictly red/black/white is handled in CSS.
  // This log is useful during dev and harmless in production.
  // eslint-disable-next-line no-console
  console.log('App initialized');
});

const request = require('supertest');
const app = require('../server');

describe('Health endpoint', () => {
  it('GET /health returns 200 and {status:"ok"}', async () => {
    const res = await request(app)
      .get('/health')
      .expect(200)
      .expect('Content-Type', /json/);
    expect(res.body).toEqual({ status: 'ok' });
  });
});

const fs = require('fs');
const path = require('path');
const { JSDOM } = require('jsdom');

describe('Hero title in index.html', () => {
  it('contains an element with id="hero-title" and expected text', () => {
    const html = fs.readFileSync(path.join(__dirname, '..', 'public', 'index.html'), 'utf8');
    const dom = new JSDOM(html);
    const doc = dom.window.document;
    const el = doc.getElementById('hero-title');
    expect(el).toBeTruthy();
    expect(el.textContent.trim()).toBe('Lab Technician');
  });
});
